/**
 * Notification model and core types for the notification system.
 *
 * All notification delivery flows through the EventBus -> NotificationService -> NotificationAdapter
 * pipeline. These types define the data that moves through that pipeline.
 */

/**
 * Supported notification channels. Each channel has a corresponding adapter
 * that implements the NotificationAdapter interface.
 */
export type NotificationChannel = 'email' | 'sms' | 'push' | 'webhook';

/**
 * Categories of notifications. Used for routing, filtering, and
 * user preference management.
 */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'welcome'
  | 'account_update'
  | 'system_alert';

/**
 * The payload passed to notification adapters for delivery.
 * Adapters receive this and format it for their specific channel.
 */
export interface NotificationPayload {
  /** Unique notification identifier. */
  id: string;
  /** The type/category of this notification. */
  type: NotificationType;
  /** Recipient identifier (email address, phone number, user ID, etc.). */
  recipient: string;
  /** Short subject line. */
  subject: string;
  /** Full notification body. */
  body: string;
  /** Channel this notification should be delivered through. */
  channel: NotificationChannel;
  /** Arbitrary metadata for adapter-specific needs. */
  metadata?: Record<string, unknown>;
}

/**
 * Result returned by adapters after attempting delivery.
 */
export interface NotificationResult {
  /** Whether delivery succeeded. */
  success: boolean;
  /** The notification that was sent. */
  notificationId: string;
  /** The channel used for delivery. */
  channel: NotificationChannel;
  /** Error message if delivery failed. */
  error?: string;
  /** Timestamp of the delivery attempt. */
  deliveredAt: Date;
}

/**
 * Persisted notification record combining payload and delivery result.
 */
export interface Notification {
  id: string;
  type: NotificationType;
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  status: 'sent' | 'failed';
  error?: string;
  sentAt: Date;
}

/**
 * NotificationAdapter interface — the contract all delivery channel adapters must implement.
 *
 * Architecture constraint: All notification channels (email, SMS, push, webhook, etc.)
 * MUST implement this interface and be registered with the NotificationService.
 * The NotificationService routes payloads to the appropriate adapter based on the
 * payload's `channel` field.
 *
 * To add a new notification channel:
 * 1. Add the channel name to NotificationChannel in src/models/notification.ts
 * 2. Create a new adapter class implementing this interface
 * 3. Register the adapter with NotificationService via its constructor
 */

import type { NotificationPayload, NotificationResult } from '../models/notification.js';

export interface NotificationAdapter {
  /** The channel this adapter handles. */
  readonly channel: string;

  /**
   * Send a notification through this channel.
   * Must return a result indicating success or failure — never throw.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs emails in-memory rather than
 * sending them through an actual SMTP/email service. Replace the `send`
 * method internals with a real email provider (SendGrid, SES, etc.)
 * for production use.
 *
 * Implements the NotificationAdapter interface required by the notification system.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  /** Email sender address (e.g. "noreply@taskflow.com"). */
  from: string;
  /** Optional reply-to address. */
  replyTo?: string;
}

export interface SentEmail {
  from: string;
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailNotificationAdapter implements NotificationAdapter {
  readonly channel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];

  constructor(private config: EmailConfig) {}

  /**
   * Send an email notification.
   * Stub implementation: stores the email in-memory and returns success.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    const email: SentEmail = {
      from: this.config.from,
      to: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: new Date(),
    };

    this.sentEmails.push(email);

    return {
      success: true,
      notificationId: payload.id,
      channel: 'email',
      deliveredAt: email.sentAt,
    };
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — handles sending notifications in response to events.
 *
 * Architecture: Event-driven with pluggable adapters.
 * - All notifications are triggered by EventBus events (never direct service calls)
 * - Delivery is routed through NotificationAdapter implementations based on channel
 * - New channels are added by implementing NotificationAdapter and registering it
 *
 * Constraints:
 * - All notification triggers MUST go through EventBus.emit()
 * - All delivery channels MUST implement NotificationAdapter
 * - Adapters are injected at construction time (dependency injection)
 *
 * Depends on:
 * - EventBus (event system) for receiving all events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<string, NotificationAdapter> = new Map();

  constructor(
    private eventBus: EventBus,
    adapters: NotificationAdapter[] = [],
  ) {
    for (const adapter of adapters) {
      this.adapters.set(adapter.channel, adapter);
    }
    this.registerEventHandlers();
  }

  /**
   * Register event handlers for all notification triggers.
   * All triggers use EventBus exclusively.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.sendNotification({
      type: 'order_confirmation',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      channel: 'email',
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    await this.sendNotification({
      type: 'order_status_update',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      channel: 'email',
    });
  }

  /**
   * Send a notification through the appropriate adapter.
   * Falls back to in-memory storage if no adapter is registered for the channel.
   */
  async sendNotification(params: {
    type: NotificationType;
    recipient: string;
    subject: string;
    body: string;
    channel: NotificationChannel;
    metadata?: Record<string, unknown>;
  }): Promise<Notification> {
    const payload: NotificationPayload = {
      id: generateNotificationId(),
      type: params.type,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      channel: params.channel,
      metadata: params.metadata,
    };

    const adapter = this.adapters.get(params.channel);

    let notification: Notification;

    if (adapter) {
      const result = await adapter.send(payload);
      notification = {
        id: payload.id,
        type: payload.type,
        recipient: payload.recipient,
        subject: payload.subject,
        body: payload.body,
        channel: payload.channel,
        status: result.success ? 'sent' : 'failed',
        error: result.error,
        sentAt: result.deliveredAt,
      };
    } else {
      this.logger.warn(`No adapter for channel "${params.channel}", storing notification without delivery`);
      notification = {
        id: payload.id,
        type: payload.type,
        recipient: payload.recipient,
        subject: payload.subject,
        body: payload.body,
        channel: payload.channel,
        status: 'sent',
        sentAt: new Date(),
      };
    }

    this.notifications.push(notification);
    this.logger.info(`Notification ${notification.id} to ${params.recipient} [${notification.status}]`);
    return notification;
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

